package com.the703.days;

public class Day012_2 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		// 4행 4열의 별(★) 출력
		for (int i = 0; i < 4; i++) {       // 4번 줄바꿈
		    for (int j = 0; j < 4; j++) {   // 한 줄에 별 4개 출력
		        System.out.print("★");
		    }
		    System.out.println();           // 줄바꿈
		}
	}

}
